/// A collection of Records managed as a batch, demonstrating
/// safe management of multiple C-allocated resources.
pub struct RecordBatch {
    records: Vec<Record>,
}

impl RecordBatch {
    pub fn new() -> Self {
        RecordBatch {
            records: Vec::new(),
        }
    }

    pub fn add(&mut self, name: &str, value: i32, data: Option<&[u8]>) -> Result<usize, RecordError> {
        let record = Record::new(name, value, data)?;
        let index = self.records.len();
        self.records.push(record);
        Ok(index)
    }

    pub fn get(&self, index: usize) -> Result<&Record, RecordError> {
        self.records.get(index).ok_or(RecordError::BoundsExceeded {
            requested: index,
            available: self.records.len(),
        })
    }

    pub fn get_mut(&mut self, index: usize) -> Result<&mut Record, RecordError> {
        let len = self.records.len();
        self.records.get_mut(index).ok_or(RecordError::BoundsExceeded {
            requested: index,
            available: len,
        })
    }

    pub fn len(&self) -> usize {
        self.records.len()
    }

    pub fn is_empty(&self) -> bool {
        self.records.is_empty()
    }

    pub fn remove(&mut self, index: usize) -> Result<Record, RecordError> {
        if index >= self.records.len() {
            return Err(RecordError::BoundsExceeded {
                requested: index,
                available: self.records.len(),
            });
        }
        Ok(self.records.remove(index))
    }
}

impl Default for RecordBatch {
    fn default() -> Self {
        Self::new()
    }
}

/// Demonstrates the interface with a simulated C library function.
/// In production, this would call actual C library functions.
///
/// This function creates a record, manipulates it, and returns the result.
pub fn process_legacy_record(
    name: &str,
    initial_value: i32,
    payload: &[u8],
) -> Result<(String, i32, Vec<u8>), RecordError> {
    // Create the record (allocates C memory)
    let mut record = Record::new(name, initial_value, Some(payload))?;

    // Simulate some processing - increment the value
    let current = record.value()?;
    record.set_value(current.checked_add(1).ok_or(RecordError::SizeOverflow)?)?;

    // Read back the results into safe Rust types
    let result_name = record.name()?.to_owned();
    let result_value = record.value()?;
    let result_data = record
        .data()?
        .map(|d| d.to_vec())
        .unwrap_or_default();

    // record is dropped here, freeing all C memory

    Ok((result_name, result_value, result_data))
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_record_creation_and_access() {
        let record = Record::new("test_record", 42, Some(b"hello")).unwrap();
        assert_eq!(record.name().unwrap(), "test_record");
        assert_eq!(record.value().unwrap(), 42);
        assert_eq!(record.data().unwrap().unwrap(), b"hello");
    }

    #[test]
    fn test_record_no_data() {
        let record = Record::new("empty", 0, None).unwrap();
        assert_eq!(record.name().unwrap(), "empty");
        assert_eq!(record.value().unwrap(), 0);
        assert!(record.data().unwrap().is_none());
    }

    #[test]
    fn test_record_empty_data() {
        let record = Record::new("empty_data", 1, Some(b"")).unwrap();
        assert!(record.data().unwrap().is_none());
    }

    #[test]
    fn test_record_mutation() {
        let mut record = Record::new("mutable", 10, Some(b"original")).unwrap();

        record.set_value(20).unwrap();
        assert_eq!(record.value().unwrap(), 20);

        record.set_name("renamed").unwrap();
        assert_eq!(record.name().unwrap(), "renamed");

        record.set_data(Some(b"updated")).unwrap();
        assert_eq!(record.data().unwrap().unwrap(), b"updated");

        record.set_data(None).unwrap();
        assert!(record.data().unwrap().is_none());
    }

    #[test]
    fn test_null_byte_in_name() {
        let result = Record::new("null\0byte", 0, None);
        assert!(matches!(result, Err(RecordError::InvalidInput(_))));
    }

    #[test]
    fn test_record_batch() {
        let mut batch = RecordBatch::new();

        batch.add("first", 1, None).unwrap();
        batch.add("second", 2, Some(b"data")).unwrap();

        assert_eq!(batch.len(), 2);
        assert_eq!(batch.get(0).unwrap().name().unwrap(), "first");
        assert_eq!(batch.get(1).unwrap().value().unwrap(), 2);

        assert!(matches!(
            batch.get(5),
            Err(RecordError::BoundsExceeded { .. })
        ));
    }

    #[test]
    fn test_record_batch_remove() {
        let mut batch = RecordBatch::new();
        batch.add("a", 1, None).unwrap();
        batch.add("b", 2, None).unwrap();

        let removed = batch.remove(0).unwrap();
        assert_eq!(removed.name().unwrap(), "a");
        assert_eq!(batch.len(), 1);
        assert_eq!(batch.get(0).unwrap().name().unwrap(), "b");
    }

    #[test]
    fn test_process_legacy_record() {
        let (name, value, data) = process_legacy_record("legacy", 99, b"payload").unwrap();
        assert_eq!(name, "legacy");
        assert_eq!(value, 100);
        assert_eq!(data, b"payload");
    }

    #[test]
    fn test_record_debug() {
        let record = Record::new("debug_test", 7, Some(b"abc")).unwrap();
        let debug_str = format!("{:?}", record);
        assert!(debug_str.contains("debug_test"));
        assert!(debug_str.contains("7"));
    }

    #[test]
    fn test_large_data() {
        let large_data = vec![0xABu8; 1024 * 1024]; // 1 MB
        let record = Record::new("large", 0, Some(&large_data)).unwrap();
        let retrieved = record.data().unwrap().unwrap();
        assert_eq!(retrieved.len(), large_data.len());
        assert_eq!(retrieved, large_data.as_slice());
    }
}

fn main() {
    println!("=== FFI Record Management Demo ===\n");

    // Create a record
    let mut record = Record::new("sensor_reading", 42, Some(b"\x01\x02\x03\x04")).unwrap();
    println!("Created: {:?}", record);

    // Modify the record
    record.set_value(100).unwrap();
    record.set_name("updated_sensor").unwrap();
    println!("Modified: {:?}", record);

    // Use the batch interface
    let mut batch = RecordBatch::new();
    batch.add("temperature", 23, Some(b"celsius")).unwrap();
    batch.add("humidity", 65, Some(b"percent")).unwrap();
    batch.add("pressure", 1013, Some(b"hPa")).unwrap();

    println!("\nBatch contains {} records:", batch.len());
    for i in 0..batch.len() {
        let r = batch.get(i).unwrap();
        println!(
            "  [{}] name={}, value={}, data={:?}",
            i,
            r.name().unwrap(),
            r.value().unwrap(),
            r.data()
                .unwrap()
                .map(|d| String::from_utf8_lossy(d).to_string())
        );
    }

    // Process a legacy record
    let (name, value, data) = process_legacy_record("legacy_input", 255, b"raw_bytes").unwrap();
    println!(
        "\nProcessed legacy record: name={}, value={}, data={:?}",
        name,
        value,
        String::from_utf8_lossy(&data)
    );

    println!("\n=== All resources will be freed on drop ===");
}